vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    float rad_lq = vRadius * length(uTexSize.xy)*0.5;
    float ang_lq = vAngle;
    vec2 uv_temp1 = (vUv - 0.5) * uTexSize.xy;
    float rad_hq = length(uv_temp1);
    float ang_hq = atan(-uv_temp1.y, uv_temp1.x);

    vec2 uv2 = (vUv - 0.5);
    float rad2 = rad_lq*0.8;
    float ang2 = ang_lq * M_INV_PI_2 + rad_lq*0.000 + uTime*0.00;


        // FIN TYPE
        float fins = q26 + 6;
        ang2 = fract(ang2*fins)/fins;
              // ENABLE THIS TO MAKE THE FINS ALTERNATE: (seamless!)
              ang2 = abs(ang2 - 0.5/fins);


    ang2 *= M_PI_2;
    vUv = 0.5 + rad2*vec2(cos(ang2),sin(ang2))*uTexSize.zw;

    ret = pow(1.25*clamp01(GetBlur1(vUv))*((texture(sampler_pc_main,vUv)-GetBlur2(vUv))), 0.333*sqrt(q31)); //invert

    uva = (vUv-0.5)*uAspect.xy+0.5 + .4/q8;
    float moon = (1./q8 / length(uva-moonpos));

    dz.x = lum(GetPixel(vUv-hor)) - lum(GetPixel(vUv+hor));
    dz.y = lum(GetPixel(vUv-ver)) - lum(GetPixel(vUv+ver));

    vec3 shine = GetPixel(vUv);
   uv2 = (vUv-moonpos)*1.4 + moonpos;
   //shine += (pow(GetPixel(uv2),2))/2;

    radi = pow(q9, .25) - .7;
    for (int n=1; n <= anz; n++)
    {
      uv2 = (normalize(vUv-moonpos)*radi+moonpos);
      shine += 2.5/anz*Get1((vUv-moonpos)*radi+moonpos,radi) ;
      radi -= 0.75/anz;;
    }

    vec3 ret_s = min(1.5*shine*sqrt(q27)*sqrt(q9), 1.5*GetPixel(vUv)*sqrt(q25*q32));

    ret = 1.2*lum(ret)/sqrt(q9) + pow(1-exp(-ret_s*1.35), 2);

//    vec2 uv_echo = (vUv - 0.5)*vec2(-1,-1) + .5; ret = mix( texture(sampler_main, vUv).xyz, texture(sampler_main, uv_echo).xyz, .5)*1; ret = 1 - ret*(1 - ret)*4; // invert


  fragColor = ret;
}
